
ALTER TABLE public.site_config
  ADD COLUMN IF NOT EXISTS about_hero_headline text NOT NULL DEFAULT 'Four Generations. One Promise.',
  ADD COLUMN IF NOT EXISTS about_hero_subtext text NOT NULL DEFAULT 'Since 1951, the Harte family has been helping Connecticut drivers — not just sell and buy cars, but feel good about the experience.',
  ADD COLUMN IF NOT EXISTS about_story text NOT NULL DEFAULT '',
  ADD COLUMN IF NOT EXISTS about_milestones jsonb NOT NULL DEFAULT '[{"year":"1951","label":"George Harte Sr. opens his first Chevrolet dealership in Connecticut"},{"year":"1970s","label":"The Harte family expands into West Haven, Wallingford & beyond"},{"year":"2014","label":"New state-of-the-art Infiniti facility built in Wallingford"},{"year":"2020s","label":"Tom & Greg Harte launch Harte Cash — a digital-first vehicle buying platform"},{"year":"Today","label":"Four generations, five locations, and 14,000+ vehicles purchased from neighbors across CT"}]'::jsonb,
  ADD COLUMN IF NOT EXISTS about_values jsonb NOT NULL DEFAULT '[{"icon":"HandshakeIcon","title":"You''re Family Here","text":"George Harte Sr. believed every customer deserves to be treated like family. Four generations later, that''s still the standard."},{"icon":"Shield","title":"Nothing Hidden, Ever","text":"Every offer includes a full breakdown. We show you exactly how we valued your vehicle."},{"icon":"Clock","title":"Your Time Matters","text":"We built this platform so you can get a real offer in under 2 minutes — not 2 hours at a dealership."},{"icon":"Award","title":"Earned Trust, Not Bought","text":"A 4.9-star rating across 2,400+ reviews doesn''t happen by accident. It comes from decades of keeping our word."}]'::jsonb;
